import React from 'react';

const STATUS_LABELS = {
  draft: 'Brouillon',
  soumis: 'Soumis',
  en_analyse: 'En analyse',
  devis_genere: 'Devis généré',
  valide: 'Validé',
  rejete: 'Rejeté',
};

export default function CourtierStats({ stats }) {
  if (!stats) return null;

  const kpis = [
    { icon: 'ti ti-folder', label: 'Dossiers total',   value: stats.total_dossiers },
    { icon: 'ti ti-loader', label: 'Dossiers actifs',  value: stats.dossiers_actifs },
    { icon: 'ti ti-file-invoice', label: 'Devis envoyés', value: stats.devis_envoyes },
    { icon: 'ti ti-users',  label: 'Clients actifs',   value: stats.clients_actifs },
  ];

  const recentCols = ['Entreprise', 'Statut', 'Score', 'Date'];

  return (
    <div>
      <div className="crt-kpi-grid">
        {kpis.map((k) => (
          <div className="crt-kpi-card" key={k.label}>
            <div className="crt-kpi-icon"><i className={k.icon} /></div>
            <div className="crt-kpi-info">
              <div className="kpi-label">{k.label}</div>
              <div className="kpi-value">{k.value}</div>
            </div>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 24 }}>
        {/* Score moyen */}
        <div className="crt-table-wrap" style={{ padding: 20 }}>
          <div style={{ fontSize: 12, color: 'var(--crt-muted)', marginBottom: 8 }}>SCORE MOYEN PORTEFEUILLE</div>
          <div style={{ fontSize: 36, fontWeight: 700, color: 'var(--crt-accent)', marginBottom: 12 }}>
            {stats.score_moyen}
          </div>
          <div className="score-bar-track" style={{ height: 8 }}>
            <div
              className="score-bar-fill"
              style={{ width: `${stats.score_moyen}%`, opacity: 0.9 }}
            />
          </div>
        </div>

        {/* Répartition */}
        <div className="crt-table-wrap" style={{ padding: 20 }}>
          <div style={{ fontSize: 12, color: 'var(--crt-muted)', marginBottom: 12 }}>RÉPARTITION PAR STATUT</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {Object.entries(stats.repartition || {}).map(([k, v]) => (
              <div key={k} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <span style={{ fontSize: 12, color: 'var(--crt-muted)', width: 110 }}>{STATUS_LABELS[k] || k}</span>
                <div className="score-bar-track" style={{ flex: 1, height: 6 }}>
                  <div
                    className="score-bar-fill"
                    style={{
                      width: stats.total_dossiers ? `${(v / stats.total_dossiers) * 100}%` : '0%',
                      opacity: 0.7,
                    }}
                  />
                </div>
                <span style={{ fontSize: 13, fontWeight: 600, width: 24, textAlign: 'right' }}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Dossiers récents */}
      <div className="crt-table-wrap">
        <div className="crt-table-header">
          <h2>Dossiers récents</h2>
        </div>
        <table className="crt-table">
          <thead>
            <tr>{recentCols.map((c) => <th key={c}>{c}</th>)}</tr>
          </thead>
          <tbody>
            {(stats.recent_dossiers || []).map((d) => (
              <tr key={d.id}>
                <td>{d.company}</td>
                <td><span className={`crt-badge badge-${d.status}`}>{STATUS_LABELS[d.status] || d.status}</span></td>
                <td>
                  {d.score != null ? (
                    <div className="crt-score-bar">
                      <div className="score-bar-track" style={{ width: 60 }}>
                        <div className="score-bar-fill" style={{ width: `${d.score}%` }} />
                      </div>
                      <span style={{ fontSize: 12, color: 'var(--crt-muted)' }}>{d.score}</span>
                    </div>
                  ) : '—'}
                </td>
                <td style={{ color: 'var(--crt-muted)', fontSize: 13 }}>{d.date_creation}</td>
              </tr>
            ))}
          </tbody>
        </table>
        {(!stats.recent_dossiers || stats.recent_dossiers.length === 0) && (
          <div className="crt-empty"><p>Aucun dossier récent</p></div>
        )}
      </div>
    </div>
  );
}
